#[test]
fn e2e_prometheus_export() {
    init_metrics_test_logging();

    tracing::info!("═══════════════════════════════════════════");
    tracing::info!("E2E: Prometheus Export Scenario");
    tracing::info!("═══════════════════════════════════════════");

    // Setup Prometheus exporter
    let exporter = opentelemetry_prometheus::exporter()
        .with_registry(Registry::new())
        .build()
        .unwrap();

    let provider = SdkMeterProvider::builder()
        .with_reader(exporter.clone())
        .build();

    let otel_metrics = OtelMetrics::new(provider.meter("asupersync"));

    let runtime = RuntimeBuilder::new()
        .metrics(otel_metrics)
        .build()
        .unwrap();

    // Generate some activity
    runtime.block_on(async {
        for _ in 0..100 {
            spawn(async {
                sleep(Duration::from_micros(100)).await;
                42
            }).await;
        }
    });

    // Get Prometheus output
    let output = exporter.registry().gather();
    let encoded = TextEncoder::new().encode_to_string(&output).unwrap();

    tracing::info!("Prometheus output:");
    for line in encoded.lines().take(20) {
        tracing::info!("  {}", line);
    }

    // Verify expected metrics present
    assert!(encoded.contains("asupersync_tasks_spawned"));
    assert!(encoded.contains("asupersync_tasks_completed"));

    tracing::info!("E2E Prometheus export completed");
}
